CREATE TYPE "WebhookSubscriptionStatus" AS ENUM ('ACTIVE','PAUSED','DISABLED');
CREATE TYPE "WebhookDeliveryStatus" AS ENUM ('PENDING','DELIVERING','SUCCEEDED','RETRY_SCHEDULED','DEAD_LETTERED','CANCELLED');
CREATE TYPE "WebhookEventStatus" AS ENUM ('PENDING','DISPATCHED','PARTIALLY_FAILED','FAILED');
CREATE TABLE "WebhookSubscription" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"applicationId" TEXT,"name" TEXT NOT NULL,"endpointUrl" TEXT NOT NULL,"eventTypes" TEXT[] NOT NULL,"status" "WebhookSubscriptionStatus" NOT NULL DEFAULT 'ACTIVE',"secretCiphertext" TEXT NOT NULL,"secretPrefix" TEXT NOT NULL,"description" TEXT,"headers" JSONB NOT NULL DEFAULT '{}',"maxAttempts" INTEGER NOT NULL DEFAULT 8,"timeoutMs" INTEGER NOT NULL DEFAULT 10000,"createdByUserId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "WebhookEvent" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"type" TEXT NOT NULL,"subjectType" TEXT,"subjectId" TEXT,"payload" JSONB NOT NULL,"status" "WebhookEventStatus" NOT NULL DEFAULT 'PENDING',"correlationId" TEXT NOT NULL,"occurredAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"dispatchedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "WebhookDelivery" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"subscriptionId" TEXT NOT NULL,"eventId" TEXT NOT NULL,"status" "WebhookDeliveryStatus" NOT NULL DEFAULT 'PENDING',"attemptCount" INTEGER NOT NULL DEFAULT 0,"nextAttemptAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"lastAttemptAt" TIMESTAMP(3),"deliveredAt" TIMESTAMP(3),"responseStatus" INTEGER,"responseBodySnippet" TEXT,"responseHeaders" JSONB,"lastError" TEXT,"durationMs" INTEGER,"deadLetteredAt" TIMESTAMP(3),"replayedFromId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE INDEX "WebhookDelivery_subscriptionId_eventId_idx" ON "WebhookDelivery"("subscriptionId","eventId");
CREATE INDEX "WebhookSubscription_organizationId_status_idx" ON "WebhookSubscription"("organizationId","status"); CREATE INDEX "WebhookEvent_organizationId_type_occurredAt_idx" ON "WebhookEvent"("organizationId","type","occurredAt"); CREATE INDEX "WebhookDelivery_organizationId_status_nextAttemptAt_idx" ON "WebhookDelivery"("organizationId","status","nextAttemptAt");
ALTER TABLE "WebhookSubscription" ADD CONSTRAINT "WebhookSubscription_applicationId_fkey" FOREIGN KEY ("applicationId") REFERENCES "DeveloperApplication"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "WebhookDelivery" ADD CONSTRAINT "WebhookDelivery_subscriptionId_fkey" FOREIGN KEY ("subscriptionId") REFERENCES "WebhookSubscription"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "WebhookDelivery" ADD CONSTRAINT "WebhookDelivery_eventId_fkey" FOREIGN KEY ("eventId") REFERENCES "WebhookEvent"("id") ON DELETE CASCADE ON UPDATE CASCADE;